parameters.query:
SELECT id, slug, name, manufacturer, category
FROM datap4k_mining_gear_norm
ORDER BY category, name;

parameters.functionCode:
var row = items[0].json;
var catLabels = {
  'mining-laser': 'Mining Laser',
  'mining-module-active': 'Mining Module (Active)',
  'mining-module-passive': 'Mining Module (Passive)',
  'mining-gadget': 'Mining Gadget'
};
var categoryLabel = catLabels[row.category] || row.category || 'Mining Gear';

function fmtMod(v) {
  if (v === null || v === undefined || v === '') return null;
  var n = Number(v);
  if (!Number.isFinite(n)) return null;
  return (n >= 0 ? '+' : '') + n + '%';
}


function parsePrices(raw) {
  if (!raw) return [];
  if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { return []; } }
  if (Array.isArray(raw)) return raw;
  return [];
}
function fmtPrice(v) {
  if (v === null || v === undefined) return null;
  var n = Number(v);
  if (!Number.isFinite(n) || n <= 0) return null;
  return n.toLocaleString('en-US', {minimumFractionDigits: 0, maximumFractionDigits: 0});
}
var uexPrices = parsePrices(row.uex_prices);
var datap4kPrices = parsePrices(row.datap4k_prices);
var hasUex = uexPrices.length > 0;
var hasDp4k = datap4kPrices.length > 0;

var lines = [];
lines.push('# ' + row.name);
lines.push('');
lines.push('- **Category:** ' + categoryLabel);
if (row.manufacturer) lines.push('- **Manufacturer:** ' + row.manufacturer);
if (row.size) lines.push('- **Size:** ' + row.size);
lines.push('');

if (row.category === 'mining-laser') {
  lines.push('## Stats');
  lines.push('');
  var statRows = [
    ['Filter Modifier', fmtMod(row.filter_modifier)],
    ['Shatter Modifier', fmtMod(row.shatter_modifier)],
    ['Charge Rate Modifier', fmtMod(row.charge_rate_modifier)],
    ['Instability Modifier', fmtMod(row.instability_modifier)],
    ['Window Size Modifier', fmtMod(row.window_size_modifier)],
    ['Catastrophic Rate Modifier', fmtMod(row.catastrophic_rate_modifier)]
  ].filter(function(r) { return r[1] !== null; });
  if (statRows.length) {
    lines.push('| Stat | Value |');
    lines.push('|---|---|');
    for (var i = 0; i < statRows.length; i++) lines.push('| ' + statRows[i][0] + ' | ' + statRows[i][1] + ' |');
  } else { lines.push('_No stat data available._'); }
} else {
  var stats = row.stats;
  if (typeof stats === 'string') { try { stats = JSON.parse(stats); } catch(e) { stats = []; } }
  if (Array.isArray(stats) && stats.length > 0) {
    lines.push('## Modifiers');
    lines.push('');
    lines.push('| Effect | Value |');
    lines.push('|---|---|');
    for (var j = 0; j < stats.length; j++) lines.push('| ' + stats[j].label + ' | ' + stats[j].value + ' |');
  } else { lines.push('## Modifiers'); lines.push(''); lines.push('_No modifier data available._'); }
}

lines.push('');
lines.push('## Availability');
lines.push('');
if (hasUex) {
  lines.push('> _Prices from UEX (live data)._');
  lines.push('');
  lines.push('| Terminal | Buy (aUEC) | Sell (aUEC) |');
  lines.push('|---|---|---|');
  for (var k = 0; k < uexPrices.length; k++) {
    var p = uexPrices[k];
    lines.push('| ' + p.terminal + ' | ' + (fmtPrice(p.buy) || '-') + ' | ' + (fmtPrice(p.sell) || '-') + ' |');
  }
} else if (hasDp4k) {
  lines.push('> _Prices from DataPack (may be outdated)._');
  lines.push('');
  lines.push('| Shop | Location | Buy (aUEC) | Sell (aUEC) |');
  lines.push('|---|---|---|---|');
  for (var m = 0; m < datap4kPrices.length; m++) {
    var dp = datap4kPrices[m];
    lines.push('| ' + dp.shop + ' | ' + dp.location + ' | ' + (fmtPrice(dp.buy) || '-') + ' | ' + (fmtPrice(dp.sell) || '-') + ' |');
  }
} else {
  lines.push('_No purchase pricing currently available._');
}

return [{ json: { item_id: row.id, slug: row.slug, name: row.name, markdown_detailed: lines.join('\n') } }];

